int countArrangement(int n) {
    int[] res = new int[]{0};
    boolean[] visited = new boolean[n+1];
    helper(n, 1, visited, res);
    return res[0];
}

void helper(int n, int idx, boolean[] visited, int[] res) {
    if (idx > n) {
        res[0]++;
    }

    for(int i=1; i<=n; i++){
        if (!visited[i] && (idx % i == 0 || i % idx == 0)) {
            visited[i] = true;
            helper(n, idx+1, visited, res);
            visited[i] = false;
        }
    }
}
